"use client";
import React, { useState, useEffect } from "react";
import { getBrandProfile, updateBrandProfile } from "@/lib/api";
import { BrandProfile, AiProviderType, StraicoUserInfo } from "@/lib/types";
import { validateClaudeKey } from "@/lib/ai/claudeService";
import {
  validateStraicoKey,
  fetchStraicoModels,
  fetchStraicoUserInfo,
} from "@/lib/ai/straicoService";
import { validateOneForAllKey } from "@/lib/ai/oneforallService";
import { ONEFORALL_MODELS, STRAICO_MODELS } from "@/lib/ai/constants";
import { Loader, CheckCircle, XCircle } from "lucide-react";
import { useAuth } from "@/lib/auth-context";

export default function SettingsPage() {
  const { user } = useAuth();
  const [profile, setProfile] = useState<BrandProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [activeProvider, setActiveProvider] =
    useState<AiProviderType>("claude");
  const [claudeApiKey, setClaudeApiKey] = useState("");
  const [straicoApiKey, setStraicoApiKey] = useState("");
  const [straicoModel, setStraicoModel] = useState("openai/gpt-4o-mini");
  const [oneforallApiKey, setOneforallApiKey] = useState("");
  const [oneforallModel, setOneforallModel] = useState(
    "anthropic/claude-4-sonnet",
  );

  const [keyValidation, setKeyValidation] = useState<{
    success: boolean;
    message: string;
  } | null>(null);
  const [keyValidating, setKeyValidating] = useState(false);

  const [straicoModels, setStraicoModels] = useState(STRAICO_MODELS);
  const [straicoUserInfo, setStraicoUserInfo] =
    useState<StraicoUserInfo | null>(null);

  useEffect(() => {
    const fetchProfile = async () => {
      if (!user?.id) {
        setLoading(false);
        return;
      }
      try {
        const data = await getBrandProfile(user.id);
        setProfile(data);
        setActiveProvider(data.aiProvider ?? "claude");
        setClaudeApiKey(data.claudeApiKey ?? "");
        setStraicoApiKey(data.straicoApiKey ?? "");
        setStraicoModel(data.straicoModel ?? "openai/gpt-4o-mini");
        setOneforallApiKey(data.oneforallApiKey ?? "");
        setOneforallModel(data.oneforallModel ?? "anthropic/claude-4-sonnet");
      } catch (error) {
        console.error("Failed to load profile:", error);
      } finally {
        setLoading(false);
      }
    };
    void fetchProfile();
  }, [user?.id]);

  const handleValidateKey = async () => {
    setKeyValidating(true);
    setKeyValidation(null);
    try {
      if (activeProvider === "claude") {
        if (!claudeApiKey) {
          setKeyValidation({ success: false, message: "Claude API key cannot be empty." });
          return;
        }
        await validateClaudeKey(claudeApiKey);
      } else if (activeProvider === "straico") {
        if (!straicoApiKey) {
          setKeyValidation({ success: false, message: "Straico API key cannot be empty." });
          return;
        }
        await validateStraicoKey(straicoApiKey);
        const [models, userInfo] = await Promise.all([
          fetchStraicoModels(straicoApiKey).catch(() => null),
          fetchStraicoUserInfo(straicoApiKey),
        ]);
        if (models && models.length > 0) setStraicoModels(models);
        setStraicoUserInfo(userInfo);
      } else if (activeProvider === "1forall") {
        if (!oneforallApiKey) {
          setKeyValidation({ success: false, message: "1ForAll API key cannot be empty." });
          return;
        }
        await validateOneForAllKey(oneforallApiKey);
      }
      setKeyValidation({ success: true, message: "API key validated successfully!" });
      await handleSaveProfile(true);
      setKeyValidation({ success: true, message: "API key validated and saved!" });
    } catch (error) {
      setKeyValidation({
        success: false,
        message: error instanceof Error ? error.message : "Validation failed.",
      });
    } finally {
      setKeyValidating(false);
    }
  };

  const handleSaveProfile = async (isAutoSave = false) => {
    if (!profile) return;
    setSaving(true);
    try {
      const updatedProfile: BrandProfile = {
        ...profile,
        aiProvider: activeProvider,
        claudeApiKey,
        straicoApiKey,
        straicoModel,
        oneforallApiKey,
        oneforallModel,
      };
      await updateBrandProfile(updatedProfile);
      setProfile(updatedProfile);
      if (!isAutoSave) alert("Settings saved successfully!");
    } catch (error) {
      console.error("Failed to save profile:", error);
      if (!isAutoSave) alert("Failed to save settings. Please try again.");
    } finally {
      setSaving(false);
    }
  };

  const updateField = (field: keyof BrandProfile, value: string) => {
    setProfile((prev) => (prev ? { ...prev, [field]: value } : prev));
  };

  if (loading) {
    return (
      <div className="bru-card bru-card--raised" style={{ display: "flex", alignItems: "center", justifyContent: "center", minHeight: 200 }}>
        <p>Loading settings...</p>
      </div>
    );
  }

  return (
    <>
      <h1 style={{ fontSize: "var(--bru-text-h3)", fontWeight: 700, marginBottom: "var(--bru-space-6)" }}>
        Settings
      </h1>

      {/* Main 2-column grid: Brand Profile (2/3) + AI Provider (1/3) */}
      <div
        className="settings-grid"
        style={{
          display: "grid",
          gridTemplateColumns: "2fr 1fr",
          gap: "var(--bru-space-6)",
        }}
      >
        {/* ── Brand Profile Card ── */}
        <div className="bru-card bru-card--raised">
          <h2 style={{ fontSize: "var(--bru-text-h5)", fontWeight: 700, marginBottom: "var(--bru-space-6)" }}>
            Brand Profile
          </h2>

          {/* Name row: 2 columns */}
          <div className="bru-form-row" style={{ marginBottom: "var(--bru-space-4)" }}>
            <div className="bru-field">
              <label htmlFor="firstName" className="bru-field__label">First Name</label>
              <input
                type="text"
                id="firstName"
                className="bru-input"
                style={{ width: "100%" }}
                value={profile?.firstName ?? ""}
                onChange={(e) => updateField("firstName", e.target.value)}
              />
            </div>
            <div className="bru-field">
              <label htmlFor="lastName" className="bru-field__label">Last Name</label>
              <input
                type="text"
                id="lastName"
                className="bru-input"
                style={{ width: "100%" }}
                value={profile?.lastName ?? ""}
                onChange={(e) => updateField("lastName", e.target.value)}
              />
            </div>
          </div>

          {/* Company + Role row */}
          <div className="bru-form-row" style={{ marginBottom: "var(--bru-space-4)" }}>
            <div className="bru-field">
              <label htmlFor="companyName" className="bru-field__label">Company Name</label>
              <input
                type="text"
                id="companyName"
                className="bru-input"
                style={{ width: "100%" }}
                value={profile?.companyName ?? ""}
                onChange={(e) => updateField("companyName", e.target.value)}
              />
            </div>
            <div className="bru-field">
              <label htmlFor="role" className="bru-field__label">Role</label>
              <input
                type="text"
                id="role"
                className="bru-input"
                style={{ width: "100%" }}
                value={profile?.role ?? ""}
                onChange={(e) => updateField("role", e.target.value)}
              />
            </div>
          </div>

          {/* Industry - full width */}
          <div className="bru-field" style={{ marginBottom: "var(--bru-space-4)" }}>
            <label htmlFor="industry" className="bru-field__label">Industry</label>
            <input
              type="text"
              id="industry"
              className="bru-input"
              style={{ width: "100%" }}
              value={profile?.industry ?? ""}
              onChange={(e) => updateField("industry", e.target.value)}
            />
          </div>

          {/* Audience */}
          <div className="bru-field" style={{ marginBottom: "var(--bru-space-4)" }}>
            <label className="bru-field__label">Audience</label>
            <div
              style={{
                border: "var(--bru-border)",
                padding: "var(--bru-space-3)",
                background: "var(--bru-cream)",
              }}
            >
              {profile?.audience.map((audience, index) => (
                <div
                  key={index}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "space-between",
                    marginBottom: index < (profile?.audience.length ?? 0) - 1 ? "var(--bru-space-2)" : 0,
                  }}
                >
                  <span style={{ fontSize: "var(--bru-text-md)", fontWeight: 500 }}>{audience}</span>
                  <button className="bru-btn bru-btn--sm">Edit</button>
                </div>
              ))}
              <button
                style={{
                  marginTop: "var(--bru-space-2)",
                  fontSize: "var(--bru-text-md)",
                  fontWeight: 700,
                  color: "var(--bru-purple)",
                  background: "none",
                  border: "none",
                  cursor: "pointer",
                  padding: 0,
                  fontFamily: "var(--bru-font-primary)",
                }}
              >
                + Add Audience
              </button>
            </div>
          </div>

          <button
            className="bru-btn bru-btn--primary"
            onClick={() => void handleSaveProfile()}
            disabled={saving}
          >
            {saving ? "Saving..." : "Save Profile"}
          </button>
        </div>

        {/* ── AI Provider Card ── */}
        <div className="bru-card bru-card--raised">
          <h2 style={{ fontSize: "var(--bru-text-h5)", fontWeight: 700, marginBottom: "var(--bru-space-6)" }}>
            AI Provider
          </h2>

          {/* Provider selector */}
          <div className="bru-field" style={{ marginBottom: "var(--bru-space-4)" }}>
            <label className="bru-field__label">Active Provider</label>
            <div style={{ display: "flex", flexDirection: "column", gap: "var(--bru-space-2)" }}>
              {([
                { value: "claude" as const, label: "Claude (Anthropic)" },
                { value: "straico" as const, label: "Straico (Proxy)" },
                { value: "1forall" as const, label: "1ForAll (Async)" },
              ]).map((provider) => (
                <label
                  key={provider.value}
                  className="bru-radio"
                  style={{
                    padding: "var(--bru-space-3)",
                    border: activeProvider === provider.value
                      ? "2px solid var(--bru-purple)"
                      : "var(--bru-border)",
                    background: activeProvider === provider.value
                      ? "rgba(174, 122, 255, 0.1)"
                      : "var(--bru-white)",
                    cursor: "pointer",
                    width: "100%",
                  }}
                >
                  <input
                    type="radio"
                    name="aiProvider"
                    value={provider.value}
                    checked={activeProvider === provider.value}
                    onChange={() => {
                      setActiveProvider(provider.value);
                      setKeyValidation(null);
                    }}
                  />
                  {provider.label}
                </label>
              ))}
            </div>
          </div>

          {/* Claude config */}
          {activeProvider === "claude" && (
            <div className="bru-field" style={{ marginBottom: "var(--bru-space-4)" }}>
              <label htmlFor="claudeApiKey" className="bru-field__label">Claude API Key</label>
              <input
                type="password"
                id="claudeApiKey"
                className="bru-input"
                style={{ width: "100%" }}
                value={claudeApiKey}
                onChange={(e) => { setClaudeApiKey(e.target.value); setKeyValidation(null); }}
                placeholder="sk-ant-..."
              />
            </div>
          )}

          {/* Straico config */}
          {activeProvider === "straico" && (
            <div className="bru-form-stack" style={{ marginBottom: "var(--bru-space-4)" }}>
              <div className="bru-field">
                <label htmlFor="straicoApiKey" className="bru-field__label">Straico API Key</label>
                <input
                  type="password"
                  id="straicoApiKey"
                  className="bru-input"
                  style={{ width: "100%" }}
                  value={straicoApiKey}
                  onChange={(e) => { setStraicoApiKey(e.target.value); setKeyValidation(null); }}
                  placeholder="Your Straico API key"
                />
              </div>
              <div className="bru-field">
                <label htmlFor="straicoModel" className="bru-field__label">Model</label>
                <select
                  id="straicoModel"
                  className="bru-select"
                  style={{ width: "100%" }}
                  value={straicoModel}
                  onChange={(e) => setStraicoModel(e.target.value)}
                >
                  {straicoModels.map((m) => (
                    <option key={m.id} value={m.id}>{m.label}</option>
                  ))}
                </select>
              </div>
              {straicoUserInfo && (
                <div
                  style={{
                    padding: "var(--bru-space-3)",
                    border: "var(--bru-border)",
                    background: "var(--bru-cream)",
                    fontSize: "var(--bru-text-md)",
                  }}
                >
                  <p style={{ fontWeight: 700 }}>{straicoUserInfo.firstName} {straicoUserInfo.lastName}</p>
                  <p>Plan: {straicoUserInfo.plan} | Coins: {straicoUserInfo.coins}</p>
                </div>
              )}
            </div>
          )}

          {/* 1ForAll config */}
          {activeProvider === "1forall" && (
            <div className="bru-form-stack" style={{ marginBottom: "var(--bru-space-4)" }}>
              <div className="bru-field">
                <label htmlFor="oneforallApiKey" className="bru-field__label">1ForAll API Key</label>
                <input
                  type="password"
                  id="oneforallApiKey"
                  className="bru-input"
                  style={{ width: "100%" }}
                  value={oneforallApiKey}
                  onChange={(e) => { setOneforallApiKey(e.target.value); setKeyValidation(null); }}
                  placeholder="Your 1ForAll API key"
                />
              </div>
              <div className="bru-field">
                <label htmlFor="oneforallModel" className="bru-field__label">Model</label>
                <select
                  id="oneforallModel"
                  className="bru-select"
                  style={{ width: "100%" }}
                  value={oneforallModel}
                  onChange={(e) => setOneforallModel(e.target.value)}
                >
                  {ONEFORALL_MODELS.map((m) => (
                    <option key={m.id} value={m.id}>{m.label}</option>
                  ))}
                </select>
              </div>
            </div>
          )}

          {/* Validate button */}
          <button
            className="bru-btn bru-btn--primary bru-btn--block"
            onClick={() => void handleValidateKey()}
            disabled={keyValidating}
          >
            {keyValidating ? (
              <>
                <Loader size={16} className="animate-spin" />
                Validating...
              </>
            ) : (
              "Validate & Save Key"
            )}
          </button>

          {keyValidation && (
            <div
              style={{
                marginTop: "var(--bru-space-2)",
                fontSize: "var(--bru-text-md)",
                fontWeight: 700,
                display: "flex",
                alignItems: "center",
                gap: "var(--bru-space-1)",
                color: keyValidation.success ? "var(--bru-success-dark)" : "var(--bru-error-dark)",
              }}
            >
              {keyValidation.success ? <CheckCircle size={16} /> : <XCircle size={16} />}
              {keyValidation.message}
            </div>
          )}

          {/* LinkedIn Integration */}
          <div className="bru-field" style={{ marginTop: "var(--bru-space-8)" }}>
            <label className="bru-field__label">LinkedIn Integration</label>
            <div
              style={{
                border: "var(--bru-border)",
                padding: "var(--bru-space-3)",
                background: "var(--bru-cream)",
                display: "flex",
                flexDirection: "column",
                gap: "var(--bru-space-2)",
              }}
            >
              <p style={{ fontSize: "var(--bru-text-md)", fontWeight: 500 }}>Status: Not Connected</p>
              <button className="bru-btn bru-btn--primary bru-btn--block">
                Connect LinkedIn
              </button>
            </div>
          </div>

          {/* Notifications */}
          <h3 style={{ fontSize: "var(--bru-text-h6)", fontWeight: 700, marginTop: "var(--bru-space-8)", marginBottom: "var(--bru-space-4)" }}>
            Notifications
          </h3>

          <div style={{ display: "flex", flexDirection: "column", gap: "var(--bru-space-3)" }}>
            <label className="bru-checkbox">
              <input type="checkbox" id="emailNotif" />
              Email Notifications
            </label>
            <label className="bru-checkbox">
              <input type="checkbox" id="slackNotif" />
              Slack Notifications
            </label>
          </div>
        </div>
      </div>

      {/* ── Brand Guidelines Card (full width) ── */}
      <div className="bru-card bru-card--raised" style={{ marginTop: "var(--bru-space-6)" }}>
        <h2 style={{ fontSize: "var(--bru-text-h5)", fontWeight: 700, marginBottom: "var(--bru-space-6)" }}>
          Brand Guidelines
        </h2>

        <div className="bru-form-row" style={{ marginBottom: "var(--bru-space-4)" }}>
          <div className="bru-field">
            <label htmlFor="copyGuideline" className="bru-field__label">Copy Guideline</label>
            <textarea
              id="copyGuideline"
              className="bru-input"
              style={{ width: "100%", minHeight: 120, resize: "vertical" }}
              value={profile?.copyGuideline ?? ""}
              onChange={(e) => updateField("copyGuideline", e.target.value)}
            />
          </div>
          <div className="bru-field">
            <label htmlFor="contentStrategy" className="bru-field__label">Content Strategy</label>
            <textarea
              id="contentStrategy"
              className="bru-input"
              style={{ width: "100%", minHeight: 120, resize: "vertical" }}
              value={profile?.contentStrategy ?? ""}
              onChange={(e) => updateField("contentStrategy", e.target.value)}
            />
          </div>
        </div>

        <div className="bru-field" style={{ marginBottom: "var(--bru-space-4)" }}>
          <label htmlFor="definition" className="bru-field__label">Brand Definition</label>
          <textarea
            id="definition"
            className="bru-input"
            style={{ width: "100%", minHeight: 120, resize: "vertical" }}
            value={profile?.definition ?? ""}
            onChange={(e) => updateField("definition", e.target.value)}
          />
        </div>

        <div style={{ display: "flex", justifyContent: "flex-end" }}>
          <button
            className="bru-btn bru-btn--primary"
            onClick={() => void handleSaveProfile()}
            disabled={saving}
          >
            {saving ? "Saving..." : "Save Guidelines"}
          </button>
        </div>
      </div>
    </>
  );
}
